class ThemeExample(Scene):
    def setup(self):
        theme = "Borland"
        apply_theme(manim_scene=self, theme_name=theme, light_theme=True)
    def construct(self):
        my_text = Text("Hello World")
        maroon_text = Text("I use Manim BTW", color=MAROON)
        maroon_text.next_to(my_text, DOWN)
        text_group = VGroup(my_text, maroon_text).move_to(ORIGIN)
        self.play(FadeIn(text_group))
